     4|/* ── Rate limiting ─────────────────────────────────────────── */
     5|const rateLimitMap = new Map<string, { count: number; resetAt: number }>();
     6|const RATE_LIMIT_MAX = 5;
     7|const RATE_LIMIT_WINDOW_MS = 60 * 60 * 1000; // 1 hora
     8|
     9|function checkRateLimit(ip: string): boolean {
    10|  const now = Date.now();
    11|  const entry = rateLimitMap.get(ip);
    12|
    13|  if (!entry || now > entry.resetAt) {
    14|    rateLimitMap.set(ip, { count: 1, resetAt: now + RATE_LIMIT_WINDOW_MS });
    15|    return true;
    16|  }
    17|
    18|  if (entry.count >= RATE_LIMIT_MAX) {
    19|    return false;
    20|  }
    21|
    22|  entry.count++;
    23|  return true;
    24|}
