    26|// Limpiar entradas expiradas cada 10 minutos
    27|setInterval(() => {
    28|  const now = Date.now();
    29|  for (const [ip, entry] of rateLimitMap.entries()) {
    30|    if (now > entry.resetAt) {
    31|      rateLimitMap.delete(ip);
    32|    }
    33|  }
    34|}, 10 * 60 * 1000);
