    36|/* ── Types ─────────────────────────────────────────────────── */
    37|interface CheckoutItem {
    38|  product_id: string;
    39|  name: string;
    40|  quantity: number;
    41|  price: number;
    42|}
    43|
    44|interface CheckoutBody {
    45|  customer_name: string;
    46|  customer_email?: string;
    47|  customer_phone: string;
    48|  shipping_address: {
    49|    address: string;
    50|    city: string;
    51|    neighborhood: string;
    52|  };
    53|  shipping_zone: string;
    54|  shipping_cost: number;
    55|  payment_method: string;
    56|  subtotal: number;
