    62|/* ── POST /api/checkout ────────────────────────────────────── */
    63|export async function POST(request: NextRequest) {
    64|  /* Rate limiting */
    65|  const ip =
    66|    request.headers.get('x-forwarded-for')?.split(',')[0]?.trim() ||
    67|    request.headers.get('x-real-ip') ||
    68|    'unknown';
    69|
    70|  if (!checkRateLimit(ip)) {
    71|    return NextResponse.json(
    72|      { error: 'Demasiados pedidos. Intentá de nuevo más tarde.' },
    73|      { status: 429 },
    74|    );
    75|  }
    76|
    77|  try {
    78|    const supabase = await createClient();
    79|
    80|    /* ── Parse body (podría ser JSON o FormData si hay comprobante) ── */
    81|    const contentType = request.headers.get('content-type') || '';
    82|    let body: CheckoutBody;
    83|    let receiptFile: File | null = null;
    84|
    85|    if (contentType.includes('multipart/form-data')) {
    86|      const formData = await request.formData();
    87|      const orderDataRaw = formData.get('order_data');
    88|      if (!orderDataRaw || typeof orderDataRaw !== 'string') {
    89|        return NextResponse.json(
    90|          { error: 'Datos del pedido no proporcionados.' },
    91|          { status: 400 },
    92|        );
    93|      }
    94|      body = JSON.parse(orderDataRaw) as CheckoutBody;
    95|      const file = formData.get('receipt');
    96|      if (file && file instanceof File) {
    97|        receiptFile = file;
    98|      }
    99|    } else {
   100|      body = (await request.json()) as CheckoutBody;
   101|    }
   102|
   103|    /* ── Validación básica ────────────────────────────────────── */
   104|    if (!body.customer_name?.trim()) {
   105|      return NextResponse.json(
   106|        { error: 'El nombre es obligatorio.' },
   107|        { status: 400 },
   108|      );
   109|    }
   110|    if (!body.customer_phone?.trim()) {
   111|      return NextResponse.json(
   112|        { error: 'El teléfono es obligatorio.' },
   113|        { status: 400 },
   114|      );
   115|    }
   116|    if (!body.items || body.items.length === 0) {
   117|      return NextResponse.json(
   118|        { error: 'El carrito está vacío.' },
   119|        { status: 400 },
   120|      );
   121|    }
   122|    if (!body.payment_method) {
   123|      return NextResponse.json(
   124|        { error: 'Seleccioná un método de pago.' },
   125|        { status: 400 },
   126|      );
   127|    }
   128|
   129|    /* ── Validar stock disponible ─────────────────────────────── */
   130|    const productIds = body.items.map((item) => item.product_id);
   131|    const { data: products, error: productsError } = await supabase
   132|      .from('products')
   133|      .select('id, name, stock, price')
   134|      .in('id', productIds);
   135|
   136|    if (productsError || !products) {
   137|      console.error('Error al verificar productos:', productsError);
   138|      return NextResponse.json(
   139|        { error: 'Error al verificar disponibilidad de productos.' },
   140|        { status: 500 },
   141|      );
   142|    }
   143|
   144|    const productMap = new Map(products.map((p) => [p.id, p]));
   145|
   146|    for (const item of body.items) {
   147|      const product = productMap.get(item.product_id);
   148|      if (!product) {
   149|        return NextResponse.json(
   150|          {
   151|            error: `El producto "${item.name}" ya no está disponible.`,
   152|            code: 'PRODUCT_NOT_FOUND',
   153|          },
   154|          { status: 400 },
   155|        );
   156|      }
   157|      if (product.stock < item.quantity) {
   158|        return NextResponse.json(
   159|          {
   160|            error:
   161|              product.stock === 0
   162|                ? `"${product.name}" está agotado.`
   163|                : `Solo quedan ${product.stock} unidades de "${product.name}".`,
   164|            code: 'INSUFFICIENT_STOCK',
   165|            product_id: item.product_id,
   166|            available: product.stock,
   167|          },
   168|          { status: 400 },
   169|        );
   170|      }
   171|    }
   172|
   173|    /* ── Construir items con datos del servidor (precio real) ── */
   174|    const orderItems = body.items.map((item) => {
   175|      const product = productMap.get(item.product_id)!;
   176|      return {
   177|        product_id: item.product_id,
   178|        product_name: product.name,
   179|        quantity: item.quantity,
   180|        unit_price: product.price,
   181|        total_price: product.price * item.quantity,
   182|      };
   183|    });
   184|
   185|    const serverSubtotal = orderItems.reduce((sum, i) => sum + i.total_price, 0);
   186|    const serverTotal = serverSubtotal + body.shipping_cost;
   187|
   188|    /* ── Insertar orden ───────────────────────────────────────── */
   189|    const { data: order, error: orderError } = await supabase
   190|      .from('orders')
   191|      .insert({
   192|        customer_name: body.customer_name.trim(),
   193|        customer_email: body.customer_email?.trim() || null,
   194|        customer_phone: body.customer_phone.trim(),
   195|        shipping_address: body.shipping_address,
   196|        shipping_zone: body.shipping_zone,
   197|        shipping_cost: body.shipping_cost,
   198|        payment_method: body.payment_method,
   199|        subtotal: serverSubtotal,
   200|        total: serverTotal,
   201|        status: 'pending',
   202|        notes: body.notes?.trim() || null,
   203|        items: orderItems,
   204|      } as Record<string, unknown>)
   205|      .select()
   206|      .single();
   207|
   208|    if (orderError || !order) {
   209|      console.error('Error al crear el pedido:', orderError);
   210|      return NextResponse.json(
   211|        { error: 'Error al crear el pedido. Intentá de nuevo.' },
   212|        { status: 500 },
   213|      );
   214|    }
   215|
   216|    /* ── Decrementar stock ────────────────────────────────────── */
   217|    for (const item of body.items) {
   218|      const product = productMap.get(item.product_id)!;
   219|      const newStock = product.stock - item.quantity;
   220|
   221|      const { error: stockError } = await supabase
   222|        .from('products')
   223|        .update({ stock: newStock })
   224|        .eq('id', item.product_id);
   225|
   226|      if (stockError) {
   227|        console.error(
   228|          `Error al actualizar stock de ${item.product_id}:`,
   229|          stockError,
   230|        );
   231|        // No fallamos la orden por esto, pero lo logueamos
   232|      }
   233|    }
   234|
   235|    /* ── Subir comprobante si existe ──────────────────────────── */
   236|    let receiptUrl: string | null = null;
   237|    if (receiptFile) {
   238|      const fileExt = receiptFile.name.split('.').pop() || 'jpg';
   239|      const filePath = `${(order as Record<string, unknown>).id}/${Date.now()}.${fileExt}`;
   240|
   241|      const { error: uploadError } = await supabase.storage
   242|        .from('receipts')
   243|        .upload(filePath, receiptFile, {
   244|          cacheControl: '3600',
   245|          upsert: false,
   246|        });
   247|
   248|      if (uploadError) {
   249|        console.error('Error al subir comprobante:', uploadError);
   250|        // No fallamos la orden por esto
   251|      } else {
   252|        const {
   253|          data: { publicUrl },
   254|        } = supabase.storage.from('receipts').getPublicUrl(filePath);
   255|        receiptUrl = publicUrl;
   256|
   257|        // Actualizar la orden con la referencia del comprobante
   258|        await supabase
   259|          .from('orders')
   260|          .update({ payment_ref: receiptUrl } as Record<string, unknown>)
   261|          .eq('id', (order as Record<string, unknown>).id);
   262|      }
   263|    }
   264|
   265|    return NextResponse.json(
   266|      {
   267|        success: true,
   268|        order: {
   269|          id: (order as Record<string, unknown>).id,
   270|          status: 'pending',
   271|          total: serverTotal,
   272|        },
   273|        receipt_url: receiptUrl,
   274|      },
   275|      { status: 201 },
   276|    );
   277|  } catch (error) {
   278|    console.error('Error inesperado en checkout:', error);
   279|    return NextResponse.json(
   280|      { error: 'Error inesperado. Por favor intentá de nuevo.' },
   281|      { status: 500 },
   282|    );
   283|  }
